import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    min_penalty = float('inf')
    best_node = None

    for index, customer_pos in enumerate(unvisited_customers):
        time_window_start, time_window_end = time_windows[index]
        distance_to_customer = np.linalg.norm(np.array(cur_truck_pos) - np.array(customer_pos))
        travel_time_to_customer = distance_to_customer / truck_speed

        arrival_time = current_time + travel_time_to_customer
        if arrival_time < time_window_start:
            waiting_time = time_window_start - arrival_time
            penalty = waiting_time + (time_window_end - arrival_time)
        elif time_window_start <= arrival_time <= time_window_end:
            penalty = time_window_end - arrival_time
        else:
            penalty = float('inf')

        if penalty < min_penalty:
            min_penalty = penalty
            best_node = index

    return best_node
